INSERT OR REPLACE INTO "exercise" VALUES(120,'exr_41n2hSGs9Q3NVGhs','Bodyweight Standing Calf Raise','Stehendes Wadenheben',NULL,NULL,'https://cdn.exercisedb.dev/w/videos/rYfe7Ll/41n2hSGs9Q3NVGhs__Bodyweight-Standing-Calf-Raise_Calves.mp4','https://cdn.exercisedb.dev/media/w/images/HbR3LMueKg.jpg',1,5,NULL,'2026-01-15 20:17:25.635881+00','2026-01-17 04:15:00.492637+00');
INSERT OR REPLACE INTO "exercise" VALUES(121,'exr_41n2hHCXQpZYhxhc','Calf Stretch With Hands Against Wall','Dehnung',NULL,NULL,'https://cdn.exercisedb.dev/w/videos/5DuR8Ot/41n2hHCXQpZYhxhc__Calf-Stretch-With-Hands-Against-Wall_Calves_.mp4','https://cdn.exercisedb.dev/media/w/images/vfYUcxlPFc.jpg',1,5,NULL,'2026-01-15 20:17:26.055467+00','2026-01-17 04:15:00.496558+00');
