INSERT OR REPLACE INTO "exercise" VALUES(123,'exr_41n2hhiWL8njJDZe','Lever Seated Calf Raise','Sitzendes Wadenheben',NULL,NULL,'https://cdn.exercisedb.dev/w/videos/HKzgIyd/41n2hhiWL8njJDZe__Lever-Seated-Calf-Raise-(plate-loaded).mp4','https://cdn.exercisedb.dev/media/w/images/9TeNhxGH3F.jpg',1,5,NULL,'2026-01-15 20:17:26.957435+00','2026-01-17 04:15:00.511211+00');
