INSERT OR REPLACE INTO "exercise" VALUES(125,'exr_41n2hcm5HH6H684G','Calf Raise from Deficit with Chair Supported','Wadenheben',NULL,NULL,'https://cdn.exercisedb.dev/w/videos/Els3cR4/41n2hcm5HH6H684G__Calf-Raise-from-Deficit-with-Chair-Supported_Calves.mp4','https://cdn.exercisedb.dev/media/w/images/po63VThsX2.jpg',1,5,NULL,'2026-01-15 20:17:27.930138+00','2026-01-17 04:15:00.495911+00');
INSERT OR REPLACE INTO "exercise_instruction" VALUES(1,1,1,'Grip the barbell with your hands slightly wider than shoulder-width apart, palms facing your feet, and lift it off the rack, holding it straight over your chest with your arms fully extended.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(2,1,2,'Slowly lower the barbell down to your chest while keeping your elbows at a 90-degree angle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(3,1,3,'Once the barbell touches your chest, push it back up to the starting position while keeping your back flat on the bench.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(4,1,4,'Repeat this process for the desired number of repetitions, always maintaining control of the barbell and ensuring your form is correct.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(5,2,1,'Sit down on the bench with your feet flat on the floor and grip the barbell with your palms facing towards you, ensuring that your hands are shoulder-width apart.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(6,2,2,'Lift the barbell off the rack and hold it directly above your chest with your arms fully extended, this is your starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(7,2,3,'Slowly lower the barbell towards your chest while keeping your elbows close to your body, pause for a moment when the barbell is just an inch away from your chest.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(8,2,4,'Push the barbell back to the starting position while exhaling, fully extending your arms but not locking your elbows. Repeat the exercise for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(9,3,1,'Lower your body towards the ground, keeping your back straight and your core engaged, until your chest is just above the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(10,3,2,'Press your body back up, extending your arms fully but not locking your elbows, while maintaining the diamond shape with your hands.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(11,3,3,'Ensure to keep your body in a straight line from your head to your heels throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(12,3,4,'Repeat this process for the desired number of repetitions, ensuring to keep your form correct throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(13,4,1,'With a dumbbell in one hand, raise your arm until it is fully extended above you, keeping your palm facing inward in a hammer grip (thumb up).',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(14,4,2,'Slowly lower the dumbbell towards your shoulder, bending your elbow and keeping the rest of your body still, until your arm forms a 90-degree angle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(15,4,3,'Push the dumbbell back up to the starting position, fully extending your arm but not locking your elbow, while exhaling and engaging your chest muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(16,4,4,'Repeat the movement for your desired amount of repetitions, then switch to the other arm and repeat the process.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(17,5,1,'Hold a dumbbell in one hand with a neutral grip (palms facing inward), at chest level, fully extending your arm upward to prepare for the press.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(18,5,2,'Slowly lower the dumbbell towards your chest, keeping your elbow close to your body and ensuring that your wrist stays straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(19,5,3,'Once the dumbbell is near your chest, push it back up to the starting position, fully extending your arm but not locking your elbow.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(20,5,4,'Repeat this movement for the desired number of repetitions before switching to the other arm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(21,6,1,'Bend your elbows to lower the dumbbell behind your head, keeping your upper arms stationary and close to your head.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(22,6,2,'Make sure your elbows are at about a 90-degree angle at the bottom of the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(23,6,3,'Push the dumbbell back up to the starting position using your triceps to lift the weight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(24,6,4,'Repeat this exercise for the desired amount of repetitions, ensuring you maintain your form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(25,7,1,'Keeping your back pressed firmly against the bench and your feet flat on the floor, push the dumbbells upward until your arms are fully extended, but do not lock your elbows.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(26,7,2,'Hold this position for a moment, making sure to keep your core engaged and your shoulders down to avoid straining your neck.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(27,7,3,'Slowly lower the dumbbells back to the starting position at shoulder level, ensuring that you control the movement rather than letting the weights drop.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(28,7,4,'Repeat this movement for your desired number of repetitions, maintaining proper form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(29,8,1,'Raise the dumbbells to shoulder height, then rotate your palms so they are facing forward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(30,8,2,'Push the dumbbells upward until your arms are fully extended above your head.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(31,8,3,'Slowly lower the dumbbells back to shoulder height while rotating your palms to face your body again.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(32,8,4,'This completes one rep; repeat the process for your desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(33,9,1,'Bend your knees slightly and using your whole body, lift the dumbbells up to your shoulders in a swift, clean motion, rotating your wrists so that your palms face forward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(34,9,2,'Once the dumbbells are at shoulder height, press them upward until your arms are fully extended, keeping your core engaged and your back straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(35,9,3,'Hold the position for a second, then slowly lower the dumbbells back to your shoulders.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(36,9,4,'Finally, bring the dumbbells back down to your sides in a controlled motion, completing one rep. Repeat this for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(37,10,1,'Push up through your hands to lift your hips off the floor, keeping your chest up and your back straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(38,10,2,'Slowly lower your body by bending your elbows until they are at about a 90-degree angle, then push your body back up to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(39,10,3,'Make sure to keep your hips close to your hands during the movement to target the triceps effectively.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(40,10,4,'Repeat this motion for the desired number of repetitions, ensuring to maintain proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(41,11,1,'Slowly bend your knees and lower your body as if you''re about to sit on a chair, keeping your chest upright and your knees over your toes.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(42,11,2,'Continue lowering yourself until your thighs are parallel or almost parallel to the floor, this is the squat position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(43,11,3,'Pause for a moment in the squat position, then push through your heels to rise back up to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(44,11,4,'Repeat this movement for the desired number of repetitions while maintaining proper form.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(45,12,1,'Engage your core and keep your chest up, then start to lower your body into a squat position by bending your knees and pushing your hips back.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(46,12,2,'Continue lowering yourself until your hips are below your knees, making sure your elbows are inside your knees at the bottom of the squat.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(47,12,3,'Pause for a moment at the bottom of the squat, then push through your heels to stand back up to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(48,12,4,'Repeat this movement for the desired number of repetitions, making sure to maintain proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(49,13,1,'Lower your body into a squat position and place your hands on the floor in front of you.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(50,13,2,'Kick your feet back quickly, extending your legs behind you and landing in a push-up position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(51,13,3,'Quickly bring your feet back towards your hands, returning to the squat position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(52,13,4,'Stand up straight again, pushing through your heels and extending your hips and knees, completing one squat thrust. Repeat this sequence for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(53,14,1,'Begin the movement by pushing your hips back and bending your knees, while simultaneously rising onto the balls of your feet. Keep your back straight and your chest up.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(54,14,2,'Lower your body as far as you can, ideally until your thighs are parallel to the floor, while keeping your heels off the ground. Your body should form a straight line from your head to your knees.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(55,14,3,'Hold the bottom position for a second, then push through the balls of your feet to rise back up to the starting position, keeping your body straight and your core engaged throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(56,14,4,'Repeat the exercise for the desired number of reps. Remember to keep a slow and controlled movement pace throughout the exercise to maximize muscle engagement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(57,15,1,'Keep your upper body straight, with your shoulders back and relaxed and chin up, then slowly lower your body as far as you can by bending your knees. Your right knee should be directly above your ankle, and your left knee should not touch the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(58,15,2,'Hold this position for a few seconds, making sure to keep your core engaged and your hips square.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(59,15,3,'Push back up to the starting position through your right heel, keeping your weight balanced evenly, not leaning forward or backward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(60,15,4,'Repeat the movement with your left leg stepping forward. Remember to do an equal number of repetitions on each side to ensure balanced strength development.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(61,16,1,'Lower your body into a squat position by bending your knees and pushing your hips back, keeping your chest upright and your knees over your toes.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(62,16,2,'Once you''re in a deep squat, push through your heels to jump up explosively, swinging the dumbbells upward to shoulder height as you rise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(63,16,3,'As you land, control your body back into the squat position, absorbing the impact with your legs, and immediately prepare for the next jump.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(64,16,4,'Repeat this process for the desired number of repetitions, maintaining a smooth and controlled rhythm throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(65,17,1,'Lower your body by bending your knees and hips, keeping your back straight and your chest upright, as if you''re trying to sit between your legs.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(66,17,2,'Continue to lower yourself until your thighs are parallel to the floor, ensuring your knees are directly above your ankles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(67,17,3,'Pause for a moment at the bottom of the squat, keeping your core engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(68,17,4,'Push through your heels to return to the starting position, straightening your legs and squeezing your glutes at the top of the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(69,18,1,'Keep your chest up and your core engaged as you lower your body down into a lunge position, bending both knees to about a 90-degree angle, while ensuring your right knee doesn''t go past your right foot.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(70,18,2,'Push through your right heel to lift your body back up to the starting position, keeping your left foot on the bench or box.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(71,18,3,'Repeat this movement for the desired number of repetitions, then switch legs and perform the same steps.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(72,18,4,'Remember to maintain good posture throughout the exercise, keeping your back straight and your gaze forward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(73,19,1,'Begin the exercise by performing a regular squat, bending your knees and pushing your hips back as if you''re about to sit on a chair.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(74,19,2,'Once you reach the lowest point of your squat, use your feet to explode upwards, jumping as high as you can.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(75,19,3,'As you land, control your body to smoothly transition back into the squat position, absorbing the impact with your legs.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(76,19,4,'Repeat this process for your desired number of repetitions, ensuring to maintain proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(77,20,1,'Shift your weight onto your left leg, and raise your right leg off the floor, extending it forward slightly.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(78,20,2,'Slowly bend your left knee, lowering your body as far as you can without losing balance, ensure your knee doesn''t go past your toes.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(79,20,3,'Pause for a moment at the bottom of the squat, then push through your left foot to straighten your leg and return to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(80,20,4,'Repeat this movement for the desired number of reps, then switch legs and do the same on the other side.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(81,21,1,'Keep your back straight and your shoulders back as you begin to bend at the hips, pushing them back while you lower the barbell along the front of your legs.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(82,21,2,'Continue lowering the barbell until it reaches mid-shin level, or until you feel a stretch in your hamstrings, making sure to keep the barbell close to your body throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(83,21,3,'After reaching this position, pause for a moment, and then slowly reverse the movement by driving your hips forward and standing back up to the starting position, squeezing your glutes at the top.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(84,21,4,'Remember to keep your core engaged and your back straight throughout the entire exercise to avoid injury.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(85,22,1,'Keeping your back straight and your head up, lower your torso by bending at the hips until it''s nearly parallel with the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(86,22,2,'As you lower your torso, keep the dumbbells as close as possible to your body and allow them to lower towards your feet.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(87,22,3,'Pause for a moment at the bottom of the movement, then reverse the motion by extending through your hips until you''re standing upright again.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(88,22,4,'Repeat this movement for the desired number of repetitions, ensuring to maintain a straight back and controlled movements throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(89,23,1,'Shift your weight onto your right foot, then slowly lift your left leg behind you while extending your right arm in front of you, keeping both parallel to the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(90,23,2,'Keep your back straight and your right knee slightly bent, as you hinge at the hips to lower your torso towards the ground, maintaining balance.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(91,23,3,'Pause for a moment when your body forms a T shape, then slowly return to the starting position, keeping your movements controlled and your core engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(92,23,4,'Repeat the exercise for the desired number of repetitions, then switch to the other leg and arm and perform the same steps.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(93,24,1,'Keeping your legs straight or with a slight bend in the knees, slowly bend at the hips, lowering the dumbbells towards the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(94,24,2,'Lower the dumbbells until you feel a stretch in your hamstrings, ensuring that your back is straight and your chest is up.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(95,24,3,'Pause briefly at the bottom of the movement, then push your hips forward and slowly lift your torso back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(96,24,4,'Repeat the movement for the desired number of repetitions, ensuring to maintain proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(97,25,1,'Slowly bend forward at the hips, keeping your back straight and extending your free leg behind you for balance.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(98,25,2,'Continue to bend forward until your torso is parallel to the floor, or as far as your flexibility allows, making sure to keep your standing leg slightly bent.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(99,25,3,'Pause for a moment at the bottom of the movement, then slowly return to the starting position, maintaining balance and control throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(100,25,4,'Repeat the exercise for your desired number of repetitions, then switch legs and perform the same number of repetitions with the other leg.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(101,26,1,'Set your desired workout settings on the machine''s console, such as time, resistance level, and incline, if available.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(102,26,2,'Begin the exercise by pushing the pedals in a smooth, gliding motion, making sure to keep your back straight and your core engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(103,26,3,'As you move your legs, also push and pull the handles with your arms, alternating as you would when naturally walking or running.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(104,26,4,'Continue the exercise for your set duration, remembering to breathe evenly throughout, and gradually slow your pace at the end for a cool-down period.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(105,27,1,'Select the Quick Start or Manual mode on the treadmill''s control panel, then gradually increase the speed to a comfortable walking pace.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(106,27,2,'Keep your back straight, your head up, and let your arms swing naturally at your sides as you walk.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(107,27,3,'Pay attention to your steps, ensuring not to step too close to the front or back of the treadmill to avoid tripping or falling.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(108,27,4,'To finish your workout, gradually decrease the speed until you come to a complete stop, then carefully step off the treadmill.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(109,28,1,'Grab onto the handlebars, which will either be stationary (for a lower body workout) or move (for a full body workout).',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(110,28,2,'Set your desired resistance and incline on the machine''s console; beginners should start with lower settings and gradually increase as their fitness improves.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(111,28,3,'Begin pedaling by pushing down on one pedal; the machine''s movement should be smooth and fluid.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(112,28,4,'Continue this motion for the duration of your workout, maintaining a steady pace, and ensure to keep your back straight and your core engaged throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(113,29,1,'Press the start button and the treadmill will begin at a slow pace, stand on the side rails while it starts moving and then step on the belt when you''re ready.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(114,29,2,'Gradually increase the speed to a comfortable jogging or running pace, ensuring your movements are smooth and controlled.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(115,29,3,'Maintain your posture, keeping your back straight, your arms at your sides, and looking straight ahead while you run.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(116,29,4,'To finish your workout, gradually decrease the speed until you''re at a slow walk, then press the stop button and step off the treadmill once it has completely stopped moving.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(117,30,1,'Set the incline level on the treadmill to a level that is challenging but manageable for you. A good starting point for beginners is an incline level of 5-10%.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(118,30,2,'Press the start button on the treadmill and begin walking at a slow pace to warm up, gradually increasing your speed as your body acclimates to the incline.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(119,30,3,'Maintain a proper posture while walking, keeping your back straight and your gaze forward, and avoid leaning into the incline.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(120,30,4,'Continue walking for a set duration or until you''ve reached your desired distance, then gradually decrease the speed and incline to cool down before stepping off the treadmill.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(121,31,1,'Stand facing the straps, grab the handles and lean back until your body is at a slight angle, keeping your feet shoulder-width apart.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(122,31,2,'Keeping your body straight and your core engaged, pull your chest up to the handles by bending your elbows and squeezing your shoulder blades together.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(123,31,3,'Pause at the top of the movement, then slowly lower your body back to the starting position, extending your arms fully.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(124,31,4,'Repeat this movement for the desired number of repetitions, maintaining control and proper form throughout each rep.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(125,32,1,'Place your opposite knee and hand on the bench for support, keeping your back flat and parallel to the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(126,32,2,'Let the arm holding the dumbbell hang down and a bit forward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(127,32,3,'Pull the dumbbell upward to the side of your torso, keeping your upper arm close to your side and keeping the torso stationary.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(128,32,4,'Lower the dumbbell back down slowly to the starting position, completing one repetition. Repeat for the desired number of reps, then switch sides.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(129,33,1,'Bend your knees slightly and lean forward from your waist until your torso is almost parallel to the floor, making sure to keep your back straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(130,33,2,'Hold onto the bench with your free hand for support, and let the hand holding the dumbbell hang down from your shoulder.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(131,33,3,'Pull the dumbbell up towards your waist, keeping your elbow close to your body and squeezing your shoulder blades together at the top of the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(132,33,4,'Lower the dumbbell back down in a controlled manner to the starting position, and repeat the exercise for your desired number of reps before switching to the other arm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(133,34,1,'Engage your core and lift your arms, chest, and legs off the ground, keeping your neck in a neutral position, this is your Superman pose.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(134,34,2,'While maintaining this pose, pull the towel towards your chest by bending your elbows and squeezing your shoulder blades together, this is your Row.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(135,34,3,'Extend your arms back out in front of you, still holding the towel, while maintaining your lifted position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(136,34,4,'Lower your arms, chest, and legs back to the ground to complete one repetition, then repeat the sequence for your desired number of reps.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(137,35,1,'Hold a towel with both hands at shoulder-width apart, and extend your arms fully in front of you at chest height.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(138,35,2,'Keeping your back straight and your core engaged, pull the towel towards your body, bending your elbows and squeezing your shoulder blades together.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(139,35,3,'Hold for a moment at the peak of the movement, then slowly extend your arms back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(140,35,4,'Repeat this movement for your desired number of repetitions, ensuring to maintain proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(141,36,1,'Lie down flat on your back on the floor, with your legs extended and your feet shoulder-width apart, holding onto the towel with both hands above your head.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(142,36,2,'Slowly slide your hands along the towel, pulling it towards your body while raising your torso slightly off the ground, keeping your core engaged throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(143,36,3,'Hold this position for a few seconds, then slowly lower your torso back to the starting position, sliding your hands back up the towel.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(144,36,4,'Repeat this exercise for the desired number of repetitions, ensuring to keep your movements controlled and your core engaged throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(145,37,1,'Slowly lower your chin towards your chest, keeping your shoulders and back still, until you feel a gentle stretch at the back of your neck.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(146,37,2,'Hold this position for about 20 to 30 seconds, breathing deeply and relaxing into the stretch.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(147,37,3,'Slowly lift your head back up to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(148,37,4,'Repeat this exercise 3-5 times, ensuring to maintain a slow, controlled movement throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(149,38,1,'While maintaining the torso stationary (no swinging), lift the left dumbbell to the front of your body while slightly bending the elbow and palms facing down. Continue to go up until your arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(150,38,2,'Inhale after the second pause and slowly lower the dumbbell back down to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(151,38,3,'Now perform the same movement for the right hand while the left hand holds the dumbbell at the waist.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(152,38,4,'Continue alternating in this manner until all of the recommended repetitions for each arm have been completed.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(153,39,1,'Place your hands lightly behind your head or across your chest, ensuring not to pull your neck with your hands as you perform the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(154,39,2,'Slowly curl your body up towards your knees, lifting your shoulder blades off the floor and contracting your abdominal muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(155,39,3,'Hold this position for a moment, feeling the tension in your abdominal muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(156,39,4,'Slowly lower yourself back down to your starting position, keeping your abs engaged even as you return to the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(157,40,1,'Keep your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(158,40,2,'Inhale and slowly begin to lower the dumbbells back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(159,40,3,'Make sure to keep your elbows close to your torso at all times.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(160,40,4,'Repeat this movement for the recommended amount of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(161,41,1,'Next, extend your arms above your head, keeping the towel taut. Your palms should be facing forward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(162,41,2,'Now, pull the towel towards your forehead by bending your elbows, while keeping your upper arms stationary. Ensure your elbows are close to your head and perpendicular to the floor. This is your starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(163,41,3,'Inhale and slowly lower the towel back to the starting position above your head, while keeping your arms extended and the towel taut.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(164,41,4,'Exhale as you curl your arms, pulling the towel back towards your forehead. This completes one rep. Repeat the exercise for your desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(165,42,1,'Place your left forearm on your left thigh, with your wrist and the dumbbell hanging over the edge of your knee, palm facing down.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(166,42,2,'Slowly curl the dumbbell up by flexing your wrist, keeping your forearm pressed against your thigh for stability.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(167,42,3,'Once your wrist is fully flexed, hold the position for a moment to maximize the contraction in the forearm muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(168,42,4,'Slowly lower the dumbbell back to the starting position, then repeat the exercise for your desired number of repetitions before switching to your right hand.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(169,43,1,'Extend your arms fully in front of you at chest level, making sure the towel is taut between your hands.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(170,43,2,'Slowly curl your arms towards your chest while keeping your elbows stationary, pulling the towel as if you were trying to bend it in half, this will engage your biceps.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(171,43,3,'Hold this position for a few seconds to maximize muscle contraction, then slowly extend your arms back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(172,43,4,'Repeat this movement for the desired amount of repetitions, ensuring to keep the towel taut and your movements controlled throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(173,44,1,'While keeping your upper arm stationary, use your biceps to curl the weight until the dumbbells are at shoulder level. Do this while keeping your palms facing your torso.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(174,44,2,'Hold the contracted position for a brief moment as you squeeze your biceps.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(175,44,3,'Slowly begin to bring the dumbbells back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(176,44,4,'Repeat the same steps for the desired amount of repetitions and then switch arms.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(177,45,1,'Rest your elbow on your thigh with your wrist just over your knee, allowing your hand to hang off the edge.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(178,45,2,'Slowly lower the dumbbell as far as possible, bending your wrist and allowing it to fully extend.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(179,45,3,'Curl the dumbbell back up towards the ceiling, flexing your wrist and using your forearm muscles to lift the weight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(180,45,4,'Repeat for the desired number of reps, then switch to the other arm and do the same.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(181,46,1,'Place a dumbbell or any weighted object in the center of the towel and hold it securely.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(182,46,2,'Keeping your elbows close to your body, slowly lift the weighted towel towards your chest by bending your elbows.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(183,46,3,'Once your hands reach chest level, pause for a moment, then slowly lower the towel back down to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(184,46,4,'Repeat this motion for your desired number of repetitions, ensuring to maintain control and proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(185,47,1,'Position your elbow on the inside of your thigh, close to your knee, with your arm fully extended.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(186,47,2,'Slowly curl the dumbbell up towards your chest, keeping your elbow stable and ensuring the movement is only happening in your forearm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(187,47,3,'Hold the position for a second, feeling the tension in your biceps.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(188,47,4,'Lower the dumbbell back down to the starting position, making sure to keep the movement controlled. Repeat the exercise for your desired number of repetitions and then switch to the other arm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(189,48,1,'Bend your knees and lift both legs off the floor, then loop the towel under your feet, holding one end of the towel in each hand.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(190,48,2,'Keep your elbows close to your body and pull the towel towards your chest, curling your legs up as you do so, similar to a hammer curl with your legs.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(191,48,3,'Pause for a moment at the top of the movement, then slowly lower your legs back down to the starting position, keeping tension in the towel.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(192,48,4,'Repeat this exercise for the desired number of repetitions, ensuring to maintain proper form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(193,49,1,'Sit down on the floor between the chairs and place your hands on the seat edges, fingers pointing towards your feet, and bend your knees so that your feet are flat on the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(194,49,2,'Push down on the chairs and lift your body off the ground, keeping your elbows bent and your shoulders down, away from your ears.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(195,49,3,'Slowly lower your body by bending your elbows until your upper arms are parallel to the floor, keeping your back straight and your core engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(196,49,4,'Push yourself back up to the starting position by straightening your arms, ensuring to keep your body straight and your core engaged throughout the movement. Repeat this exercise for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(197,50,1,'Extend your right arm straight out in front of you at shoulder height, keeping your palm facing down.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(198,50,2,'Gently pull your right arm across your body using your left hand, applying light pressure until you feel a stretch in your shoulder.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(199,50,3,'Hold this position for about 20 to 30 seconds, making sure to breathe deeply throughout the stretch.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(200,50,4,'Release the stretch and repeat the same steps on the other side with your left arm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(201,51,1,'Next, raise your legs parallel to the ground into an L-shape, keeping your legs straight and together; this is your starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(202,51,2,'Using your upper body strength, pull yourself up until your chin is above the bar, while maintaining the L-shape with your legs.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(203,51,3,'Hold this position for a moment, ensuring your core is engaged and your body is in a straight line.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(204,51,4,'Finally, lower yourself back down in a controlled manner to the starting position, keeping your legs in the L-shape throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(205,52,1,'With your palms facing away from your body, reach up and grab the bar with a wide grip, keeping your arms fully extended.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(206,52,2,'Next, engage your core and lift your hips off the ground, pulling your body upwards towards the bar in an inverted position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(207,52,3,'As you reach the top of the movement, use your arms to assist in pulling your body up and over the bar, while keeping your legs straight and together.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(208,52,4,'Slowly lower yourself back down to the starting position, maintaining control throughout the movement to ensure that you''re using your muscles rather than momentum.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(209,53,1,'Pull your body up by driving your elbows towards the floor, keep pulling until your chin is above the bar, while keeping your body straight and core engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(210,53,2,'At the top of the movement, pause for a second, then slowly lower your body back down to the starting position, maintaining control throughout the descent.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(211,53,3,'Ensure your arms are fully extended before starting the next repetition.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(212,53,4,'Repeat the process for the desired number of repetitions, making sure to maintain proper form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(213,54,1,'Reach up and grip the bar with one hand closer to you and the other further away, in an overhand grip. Your hands should be shoulder-width apart, forming a line across your body.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(214,54,2,'Pull your body up towards the bar while twisting your torso towards the hand that is closer to you. Your aim is to touch your shoulder to the bar.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(215,54,3,'Lower your body back down to the starting position in a controlled manner, ensuring to keep your body straight and not to swing.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(216,54,4,'Repeat the exercise on the other side by switching your hand positions and twisting your torso in the opposite direction.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(217,55,1,'Stand between the chairs and grip the backs or the seats of the chairs with each hand, ensuring your grip is firm and secure.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(218,55,2,'Slowly lift your body off the ground by pulling up with your arms and shoulders, bending your knees at a 90-degree angle as you rise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(219,55,3,'Hold this position for a few seconds, feeling the tension in your upper body and core muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(220,55,4,'Gradually lower your body back down to the starting position, keeping your knees bent, then repeat the exercise for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(221,56,1,'Pull your shoulder blades down and back, bend your legs at the knees if necessary, and cross your ankles behind you.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(222,56,2,'Engage your core and pull yourself up until your chin is above the bar, maintaining control and not using momentum to swing your body up.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(223,56,3,'Hold the position at the top for a moment, ensuring your chest is close to the bar and your shoulder blades are fully retracted.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(224,56,4,'Slowly lower yourself back down to the starting position, fully extending your arms while maintaining control of your movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(225,57,1,'With a firm grip on the bar, pull your shoulder blades down and back, bend your legs at the knees if necessary, and cross your ankles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(226,57,2,'Engage your core and pull your body up until your chin is above the bar while keeping your elbows close to your body.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(227,57,3,'Hold this position for a moment, ensuring your chest is close or touching the bar.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(228,57,4,'Slowly lower your body back down to the starting position, fully extending your arms and maintaining control throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(229,58,1,'Lift your hips up towards the ceiling, straightening your legs and pushing your heels down towards the floor to form an inverted V shape with your body.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(230,58,2,'Spread your fingers wide on the mat and press down through your palms, keeping your head between your arms and looking towards your knees.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(231,58,3,'Make sure your back is flat, and your weight is evenly distributed between your hands and feet.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(232,58,4,'Hold this position for a few breaths, then gently lower your body back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(233,59,1,'Extend your right arm out in front of you, with your palm facing down.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(234,59,2,'With your left hand, gently grasp the fingers of your extended right hand.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(235,59,3,'Slowly pull the fingers of your right hand towards your body until you feel a stretch along the top of your wrist and forearm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(236,59,4,'Hold this stretch for about 15 to 30 seconds, then release and switch to the other hand. Repeat this process for both hands as needed.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(237,60,1,'Bend forward at the waist so your chest is leaning forward over your feet. Keep your back straight and let your arms hang straight down, palms facing each other.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(238,60,2,'Keep a slight bend in your elbows and raise your arms out to the sides until they''re at shoulder level, like you''re spreading your wings. This is the fly part of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(239,60,3,'Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(240,60,4,'Repeat this movement for your desired number of repetitions, remembering to keep your core engaged and back straight throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(241,61,1,'Bend your knees, bring the soles of your feet together, and draw your heels as close to your body as you can, forming a diamond shape with your legs.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(242,61,2,'Hold onto your feet or ankles, keeping your elbows slightly bent and directed towards your knees.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(243,61,3,'Inhale deeply, and as you exhale, press your knees down towards the floor, trying to make them touch the ground; this will stretch your inner thighs and hips.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(244,61,4,'Hold this pose for 3-5 breaths, or as long as comfortable, then gently release your legs and return to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(245,62,1,'Push your body up onto your forearms and toes, making sure your elbows are directly under your shoulders and your forearms are facing forward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(246,62,2,'Keep your body in a straight line from your head to your feet, ensuring your back is flat and your hips are not dropping or rising.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(247,62,3,'Engage your core muscles and hold this position for as long as you can, ideally aiming for 30 seconds to 1 minute.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(248,62,4,'Lower your body back to the starting position in a controlled manner and repeat the exercise as desired.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(249,63,1,'Align your upper thighs or hips with the larger pad, allowing your torso to bend forward from the waist and hang down.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(250,63,2,'Keeping your back straight, cross your arms over your chest or place your hands behind your head.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(251,63,3,'Slowly lift your torso until your body is in a straight line, using your lower back muscles to perform the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(252,63,4,'Lower your body back down to the starting position, ensuring you don''t bend too far forward, and repeat the movement for your desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(253,64,1,'Keep your body straight and bend at your waist while keeping your back flat, continue to lower your torso until you feel a mild stretch on the hamstrings.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(254,64,2,'Begin to raise your torso by extending through the hips with your back still kept straight, continue this movement until your body is in line with your legs.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(255,64,3,'Hold this position for a few seconds, focusing on squeezing your glutes and hamstrings at the top of the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(256,64,4,'Slowly lower your body back to the starting position, repeating the movement for the desired amount of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(257,65,1,'Sit on a bench with your back to the cable machine, holding the ends of the rope handle in each hand, and position your hands at the base of your neck.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(258,65,2,'Keep your back straight and your head facing forward, then slowly extend your neck backward, pulling the rope upward until you feel a stretch in your neck muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(259,65,3,'Pause for a moment at the top of the extension, then slowly return to the starting position, making sure to maintain control throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(260,65,4,'Repeat this exercise for your desired number of repetitions, ensuring you keep your movements slow and controlled to avoid injury.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(261,66,1,'Hold a light weight in your hand, such as a dumbbell or a can of soup, with your palm facing down.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(262,66,2,'Slowly lift the weight by extending your wrist upwards, taking care not to move your forearm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(263,66,3,'Hold this position for a few seconds, feeling the tension in your wrist and forearm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(264,66,4,'Gradually lower your hand back to the starting position, completing one repetition. Repeat this exercise for the desired number of sets.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(265,67,1,'Slowly tilt your head back, looking up towards the ceiling, to create an extension in your neck. Hold this position for 5 to 10 seconds.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(266,67,2,'Return your head to the neutral position, looking straight ahead.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(267,67,3,'Now, gently tilt your head forward, bringing your chin towards your chest, to create an inclination in your neck. Hold this position for 5 to 10 seconds.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(268,67,4,'Repeat these movements for the desired number of reps, ensuring to move slowly and smoothly to prevent any strain or injury.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(269,68,1,'Slowly lower your chin towards your chest to create a flexion in the neck, hold for a few seconds.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(270,68,2,'Gradually lift your head back up to the starting position, then gently tilt your head backwards to create an extension in the neck, hold for a few seconds.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(271,68,3,'Return to the starting position and repeat the exercise for the recommended number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(272,68,4,'Remember to keep the movements slow and controlled, and avoid any sudden jerks or twists to prevent injury.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(273,69,1,'Extend your arms forward and grip the bar with your palms facing up, this is the supination position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(274,69,2,'Slowly lean back, keeping your feet flat on the ground, and allow your arms to fully extend while maintaining your grip on the bar.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(275,69,3,'Hold this stretching position for about 20 to 30 seconds, ensuring you feel a stretch in your arms and shoulders.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(276,69,4,'Return to the starting position by slowly standing back up and releasing your grip on the bar, then repeat the exercise for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(277,70,1,'Slowly bend your elbow, bringing your hand towards your shoulder while keeping your upper arm still.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(278,70,2,'Hold this position for a few seconds to feel the stretch in your bicep muscle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(279,70,3,'Slowly straighten your elbow, lowering your hand back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(280,70,4,'Repeat this movement for the desired number of repetitions, then switch to the other arm.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(281,71,1,'Sit on the bench of the cable machine, facing away from the pulley, and place the rope handle behind your head, holding each end with your hands.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(282,71,2,'With your back straight and your eyes looking forward, slowly flex your neck forward, bringing your chin towards your chest while resisting the pull of the cable.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(283,71,3,'Pause for a moment when your chin is near your chest, then slowly return to the starting position, maintaining control and resisting the pull of the cable.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(284,71,4,'Repeat this motion for the desired number of repetitions, making sure to keep your movements slow and controlled throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(285,72,1,'Keeping your torso stationary, lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to lift them until they are at shoulder level.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(286,72,2,'Pause for a second at the top of the movement, then slowly lower the weights back down to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(287,72,3,'Repeat this movement for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(288,72,4,'Remember to keep your spine neutral and your movements controlled throughout the exercise, avoiding any swinging or jerking.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(289,73,1,'Place your toes on the lower portion of the platform with your heels extending off, and adjust the pads so they fit snugly against your lower thigh, just above your knees.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(290,73,2,'Slowly raise your heels by pushing up on the balls of both feet, making sure to exhale as you perform this movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(291,73,3,'Hold the contracted position briefly at the top before slowly lowering your heels back to the original position, inhaling as you do so.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(292,73,4,'Repeat this motion for the desired number of repetitions, ensuring to maintain a controlled movement speed throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(293,74,1,'Slowly lift your heels off the ground so that you''re standing on your tiptoes.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(294,74,2,'Hold this position for a moment, ensuring you''re engaging your calf muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(295,74,3,'Slowly lower your heels back to the ground, returning to your starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(296,74,4,'Repeat this exercise for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(297,75,1,'Lift one leg off the ground, keeping it straight, until it forms a 90-degree angle with your body.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(298,75,2,'Hold this position for a few seconds, then slowly lower your leg back down to the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(299,75,3,'Repeat the same movement with your other leg, keeping your lower back pressed against the floor throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(300,75,4,'Continue alternating between both legs for the desired number of repetitions, ensuring your movements are controlled and deliberate.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(301,76,1,'Position your feet shoulder-width apart on the platform, with your toes facing forward and your heels extending off the edge.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(302,76,2,'Slowly lower your heels towards the ground, stretching your calf muscles as much as possible.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(303,76,3,'Then, push through the balls of both feet to raise your body upward, ensuring your knees are kept straight and your abdominal muscles are engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(304,76,4,'Lower your heels back down slowly to the starting position and repeat the exercise for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(305,77,1,'Slowly raise your heels off the ground, putting your weight onto the balls of both feet.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(306,77,2,'Ensure your abdominal muscles are engaged and your back is straight as you rise to your tiptoes.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(307,77,3,'Pause for a moment at the top of the movement, feeling the contraction in your calf muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(308,77,4,'Slowly lower your heels back to the ground to complete one repetition, and repeat this process for your desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(309,78,1,'Slowly lift your legs off the ground, keeping them straight and together, until they form a 90-degree angle with your body.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(310,78,2,'Hold this position for a few seconds, keeping your core engaged and your lower back pressed into the floor to avoid straining.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(311,78,3,'Lower your legs back down in a controlled manner, making sure not to let your feet touch the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(312,78,4,'Repeat this exercise for the desired number of repetitions, ensuring to maintain proper form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(313,79,1,'Slowly raise your heels off the ground, shifting your weight onto the balls of your feet while keeping your abdominal muscles pulled in so that you move straight upward, not forward or backward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(314,79,2,'Hold the position for a moment, ensuring your calves are flexed and you''re balanced on the balls of your feet.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(315,79,3,'Gradually lower your heels back to the ground to return to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(316,79,4,'Repeat this movement for your desired number of repetitions, ensuring to keep your movements slow and controlled.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(317,80,1,'Keep your arms straight and slowly lift the towel out to your sides until your arms are parallel to the floor, maintaining tension on the towel throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(318,80,2,'Pause for a moment at the top of the movement, making sure to keep your shoulders down and not hunch them up towards your ears.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(319,80,3,'Slowly lower the towel back down to the starting position, keeping your arms straight and maintaining the tension on the towel.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(320,80,4,'Repeat this movement for your desired number of repetitions, ensuring to keep your core engaged and your movements controlled throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(321,81,1,'Take a big step forward with your right foot, keeping your left foot in place.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(322,81,2,'Lower your body until your right knee forms a 90-degree angle, making sure your right knee is directly above your right ankle and your left knee is hovering just above the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(323,81,3,'Push off your right foot to return to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(324,81,4,'Repeat the movement with your left leg, alternating legs for each repetition.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(325,82,1,'Lift your right knee as high as you can, then step forward while lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(326,82,2,'As you move into the lunge, swing your arms as if you are running, with the opposite arm and leg moving together.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(327,82,3,'Push off with your right foot and return to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(328,82,4,'Repeat the exercise with your left leg, and continue to alternate between legs for the duration of your workout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(329,83,1,'Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be directly above your right ankle and your left knee should be hovering just above the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(330,83,2,'Push off with your right foot, bringing your left foot forward to step into the next lunge. This completes one rep.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(331,83,3,'Repeat this motion, alternating legs as you move forward across the room.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(332,83,4,'Remember to keep your upper body straight and your core engaged throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(333,84,1,'Take a step back with your right foot, keeping your left foot in place.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(334,84,2,'Lower your body until your left thigh is parallel to the ground and your right knee is hovering just above the floor, ensuring your left knee is directly above your left ankle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(335,84,3,'Push off your right foot and return to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(336,84,4,'Repeat the process with your left leg stepping back, and continue to alternate legs for the duration of your workout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(337,86,1,'Take a step backward with your right foot, lowering your body into a lunge position. Your left knee should be directly above your left ankle and your right knee should be hovering just off the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(338,86,2,'Maintain a straight posture with your chest up and your gaze straight ahead, ensuring that your back knee is close but not touching the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(339,86,3,'Push off your right foot, returning to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(340,86,4,'Repeat the exercise with your left leg stepping backward, alternating legs for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(341,87,1,'Take a big step to the right with your right foot, keeping your left foot in place.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(342,87,2,'Bend your right knee and push your hips back, lowering your body into a lunge position on your right side. Keep your left leg straight and your right knee directly above your right foot.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(343,87,3,'Push through your right foot to return to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(344,87,4,'Repeat the movement on your left side to complete one repetition. Continue to alternate sides for your desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(345,88,1,'Lower your body down towards the floor, bending your elbows and keeping your body straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(346,88,2,'As you push your body back up, rotate your upper body to the right, extending your right arm towards the ceiling while keeping your left hand on the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(347,88,3,'Return to the starting position and repeat the push-up, this time rotating your upper body to the left and extending your left arm towards the ceiling.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(348,88,4,'Continue to alternate sides with each push-up, ensuring you maintain proper form and control throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(349,89,1,'Slowly extend the front leg straight out in front of you, keeping your foot flat on the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(350,89,2,'Carefully lift the toes of the extended leg towards the ceiling, keeping your heel on the ground, until you feel a stretch in the back of your thigh.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(351,89,3,'Hold this position, ensuring your back is straight and your hips are square, for 20 to 30 seconds to allow the hamstring muscle to stretch.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(352,89,4,'Switch legs and repeat the process.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(353,90,1,'Raise your fists to your chin level, keep your elbows close to your body, and maintain a relaxed posture.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(354,90,2,'Extend your right arm straight out in front of you, as if you are punching something, while rotating your fist so your palm is facing the ground at the end of the punch.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(355,90,3,'Quickly retract your right arm back to the starting position and simultaneously extend your left arm in the same punching motion.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(356,90,4,'Repeat these movements, alternating between your right and left arm, and maintain a steady rhythm for the duration of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(357,91,1,'Extend your arms straight up towards the ceiling, ensuring that your elbows are directly above your shoulders and your wrists are in line with your elbows.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(358,91,2,'Slowly bend your elbows, lowering the dumbbells down towards your temples, while keeping your elbows stationary and your upper arms perpendicular to the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(359,91,3,'Once the dumbbells are near your temples, pause for a moment, then use your triceps to extend your arms back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(360,91,4,'Repeat this movement for the desired number of repetitions, making sure to keep your elbows in place and use your triceps to lift the dumbbells.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(361,92,1,'Grasp the handles firmly, keeping your back straight and your feet flat on the pedals.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(362,92,2,'Start pedaling at a moderate pace to warm up, ensuring that your movements are smooth and controlled.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(363,92,3,'Gradually increase your speed while also pushing and pulling the handles back and forth in rhythm with your pedaling.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(364,92,4,'Continue this for a set duration or until you have reached your desired distance, then gradually reduce your speed for a cool down period.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(365,93,1,'Lift your right leg straight out in front of you while keeping your left foot firmly on the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(366,93,2,'As you lift your right leg, bend at the waist and touch your right foot with your left hand, keeping your right hand extended.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(367,93,3,'Return to the initial position and repeat the same movement, this time lifting your left leg and touching it with your right hand.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(368,93,4,'Continue to alternate between right and left for your desired number of repetitions, maintaining a steady rhythm throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(369,94,1,'Push up from the ground one arm at a time into a push-up position, keeping your body as stable and straight as possible.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(370,94,2,'Once you''re in the push-up position, lower yourself back down one arm at a time to the original plank position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(371,94,3,'Ensure that your core is engaged and your back is straight throughout the exercise to maintain proper form.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(372,94,4,'Repeat this movement for a set number of repetitions or for a specific time period, remembering to alternate the arm you start with each time.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(373,95,1,'Keep your core engaged and your back flat.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(374,95,2,'Then, slowly lift your right foot off the ground and move it out to the side, tapping the toe on the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(375,95,3,'Bring your right foot back to the starting position and repeat the same movement with your left foot.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(376,95,4,'Continue alternating between your right and left foot for the desired number of repetitions or time.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(377,96,1,'Ensure your core is engaged, your back is flat, and your body is in a straight line.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(378,96,2,'Slowly lift one leg off the ground, keeping it straight and not allowing your hips to dip or twist.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(379,96,3,'Hold this position for a few seconds, ensuring your core remains engaged and your body stays aligned.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(380,96,4,'Lower your leg back down to the starting position and repeat the process with the other leg.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(381,97,1,'Slowly raise your heels off the ground while keeping your toes firmly planted on the floor, this movement should focus on the articulation of your ankles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(382,97,2,'Hold this position for a moment, feeling the stretch in your calves and the engagement of your ankle muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(383,97,3,'Slowly lower your heels back down to the ground, returning your feet to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(384,97,4,'Repeat this exercise for the desired number of reps, ensuring to maintain control and precision throughout each movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(385,98,1,'Slowly lift the front part of your foot off the ground, keeping your heel in place, this movement should come from your ankle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(386,98,2,'Hold this position for a few seconds, feeling the stretch in your calf and the back of your ankle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(387,98,3,'Slowly lower your foot back to the ground, returning to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(388,98,4,'Repeat this exercise 10-15 times, then switch to the other foot and perform the same number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(389,99,1,'Slowly extend one foot out in front of you, keeping your heel on the ground and lifting your toes towards the sky to stretch your ankle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(390,99,2,'Hold this position for about 20 to 30 seconds, feeling the stretch in your calf and the back of your ankle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(391,99,3,'Slowly lower your foot back to the starting position and repeat the stretch with the other foot.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(392,99,4,'Perform this exercise for several repetitions, alternating between each foot, for best results.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(393,100,1,'Slowly extend your feet forward, pointing your toes away from your body as far as you can comfortably go.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(394,100,2,'Hold this position for about 20-30 seconds, feeling a gentle stretch in your ankles and the arches of your feet.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(395,100,3,'Next, flex your feet by pulling your toes back towards your body, again holding for 20-30 seconds to stretch the backs of your ankles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(396,100,4,'Repeat these steps for several rounds, taking care not to overstretch or cause pain.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(397,101,1,'Lift one foot off the ground and keep your leg either straight or slightly bent at the knee, depending on your comfort level.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(398,101,2,'Begin to rotate your foot in a circular motion, moving it clockwise for about 10 rotations.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(399,101,3,'After completing the clockwise rotations, switch to counter-clockwise rotations for another 10 times.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(400,101,4,'Lower your foot back to the ground and repeat the same process with your other foot.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(401,102,1,'Then, flex your feet and ankles, pointing your toes towards your body.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(402,102,2,'Slowly move your feet and ankles side to side, keeping your legs straight and stationary.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(403,102,3,'Ensure you''re moving from your ankles, not your hips or knees.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(404,102,4,'Continue this motion for about 30 seconds to a minute, then rest and repeat as desired.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(405,103,1,'Lower your body towards the ground, keeping your elbows close to your body and your core engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(406,103,2,'Push your body upwards with enough force to lift your hands off the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(407,103,3,'While in mid-air, quickly clap your hands together and then place them back in the original position before you land.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(408,103,4,'Land softly, absorbing the impact with your arms, and immediately begin your next repetition.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(409,104,1,'Lower your body towards the ground, keeping your back straight and your core engaged, until your chest is just above the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(410,104,2,'Press your body back up to the starting position, making sure to keep your elbows close to your body throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(411,104,3,'Ensure to inhale as you lower your body and exhale as you push back up.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(412,104,4,'Repeat this exercise for the desired number of repetitions, maintaining the diamond shape with your hands throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(413,105,1,'Walk your feet up onto the bench or step, keeping your body straight from your head to your heels, this will be your starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(414,105,2,'Lower your body towards the ground while keeping your elbows close to your body until your chest nearly touches the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(415,105,3,'Push your body up back to the starting position by fully extending your arms, while maintaining your body straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(416,105,4,'Repeat the process for the desired number of repetitions, ensuring to keep your core tight and back flat throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(417,106,1,'Push up through your hands, extending your arms and arching your back, lifting your upper body off the floor while keeping your hips and legs down, similar to the upward dog yoga pose.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(418,106,2,'Hold this position for a few seconds, ensuring your shoulders are pulled back and away from your ears, and your neck is in a neutral position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(419,106,3,'Lower your body back down to the starting position by bending your elbows and lowering your chest back towards the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(420,106,4,'Repeat this exercise for the desired number of reps, ensuring to keep your movements slow and controlled to maximize the effectiveness of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(421,107,1,'Lower your body until your chest is close to the floor, keeping your back straight and your elbows close to your body.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(422,107,2,'Push your body up, extending your arms fully but without locking your elbows, while maintaining your body in a straight line.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(423,107,3,'Pause for a moment at the top of the push-up.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(424,107,4,'Lower your body back down to the starting position, ensuring you don''t drop your body too quickly, and repeat the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(425,108,1,'Extend your legs behind you and balance on the balls of your feet, forming a straight line from your head to your heels.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(426,108,2,'Lower your body towards the floor by bending your elbows, keeping your body straight and your elbows close to your sides.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(427,108,3,'Push your body back up by extending your arms, keeping your body straight and your core engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(428,108,4,'Repeat the exercise for the desired amount of repetitions, making sure to maintain the correct form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(429,109,1,'Extend your legs behind you, with your toes on the ground, so your body is in a straight line from your head to your heels.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(430,109,2,'Lower your body towards the elevated surface by bending your elbows until your chest nearly touches the surface.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(431,109,3,'Push your body back up to the starting position by straightening your arms, making sure to keep your body straight and your core engaged throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(432,109,4,'Repeat the exercise for your desired number of repetitions, ensuring to maintain proper form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(433,110,1,'Slowly bend your elbows, lowering your body towards the floor in a controlled manner while keeping your core tight and your body straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(434,110,2,'Continue to lower yourself until your head lightly touches the ground or as far as your strength allows.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(435,110,3,'Then, push back up by straightening your arms, returning to the starting handstand position, while maintaining a rigid body line.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(436,110,4,'Repeat these steps for the desired number of reps, always ensuring to keep your movements controlled and your form correct.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(437,111,1,'Push your hips back and upwards into a downward dog or pike position, keeping your hands firmly planted on the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(438,111,2,'Lower your body towards the ground, bending your elbows as you would in a regular push-up, but as you descend, allow your hips and chest to move towards the ground as well, transitioning into a cobra or upward facing dog position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(439,111,3,'Push your body back up by straightening your arms, lifting your chest and hips off the ground, and returning to the pike position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(440,111,4,'Repeat these movements for your desired amount of repetitions, ensuring to maintain proper form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(441,112,1,'Lean your body forward to put emphasis on the chest muscles and bend your knees, crossing your ankles behind you to maintain balance.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(442,112,2,'Slowly lower your body by bending your elbows until you reach a point where your elbows are at a 90-degree angle and your chest is level with the bars.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(443,112,3,'Pause for a moment at the bottom of the movement, then push yourself back up to the starting position, extending your arms fully but without locking your elbows.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(444,112,4,'Repeat this process for the desired number of repetitions, ensuring to keep your body leaned forward throughout the exercise to maintain focus on the chest muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(445,113,1,'Slowly lower your body by bending your elbows while keeping them close to your body until your upper arms are parallel to the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(446,113,2,'Hold this position for a moment, ensuring your back is close to the bar and your shoulders are down.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(447,113,3,'Push your body back up to the starting position by extending your arms, but don''t lock your elbows.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(448,113,4,'Repeat these steps for the desired number of repetitions, maintaining the proper form throughout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(449,114,1,'Place your hands shoulder-width apart on the bench or chair, extend your legs out in front of you, and move your body forward so that your back is just in front of the bench.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(450,114,2,'Slowly lower your body by bending your elbows until they form a 90-degree angle, ensuring your back is close to the bench.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(451,114,3,'Once you reach the bottom of the movement, push your body back up using your triceps to bring your body back to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(452,114,4,'Repeat this movement for your desired number of repetitions, ensuring to maintain proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(453,115,1,'Push your hips up by straightening your arms, keeping your hands and feet in place, and your body should be lifted off the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(454,115,2,'Lower your body back down by bending your elbows until your buttocks almost touch the floor, but do not rest your body weight on the floor.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(455,115,3,'Push your body back up by straightening your arms again, returning to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(456,115,4,'Repeat this movement for a set number of repetitions, ensuring you maintain control and proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(457,116,1,'Bend your knees to sit down and place your hands on the edge of the chair, fingers pointing towards your body.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(458,116,2,'Push off your hands and slide your bottom off the chair, lowering your body towards the floor by bending your elbows until they are at about a 90-degree angle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(459,116,3,'Push your body back up using your arms until they are fully extended, ensuring your hips are close to the chair and your chest is lifted.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(460,116,4,'Repeat this process for your desired number of repetitions, ensuring to maintain proper form throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(461,117,1,'Push your hips upward into a bridge position, keeping your upper back and shoulders on the ground, and your hands by your sides.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(462,117,2,'Slowly slide your feet away from your body using the towel, extending your legs fully while keeping your hips elevated.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(463,117,3,'After fully extending your legs, slowly pull your feet back towards your body, using your hamstrings and glutes to pull while maintaining the bridge position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(464,117,4,'Lower your hips back to the floor to complete one repetition, then repeat this process for the desired number of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(465,118,1,'Grasp the handles of the machine, keeping your arms slightly bent and your back straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(466,118,2,'Push one pedal down while allowing the other to rise, mimicking a stepping motion.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(467,118,3,'Continue the stepping motion, alternating between your left and right foot.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(468,118,4,'Maintain a steady pace, ensuring to engage your core and keep your back straight throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(469,119,1,'Start by holding the handles of the jump rope at waist height, with your elbows close to your body and your wrists slightly above your waist.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(470,119,2,'Begin to swing the rope over your head, using your wrists and forearms to generate the motion rather than your entire arms.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(471,119,3,'As the rope approaches your feet, jump off the ground using both feet at the same time, just high enough to allow the rope to pass underneath.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(472,119,4,'Continue the motion, jumping each time the rope comes around, and aim to maintain a steady rhythm for the duration of your workout.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(473,120,1,'Slowly raise your heels off the ground until you''re standing on your tiptoes.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(474,120,2,'Hold this position for a moment, ensuring that the contraction is felt in your calves.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(475,120,3,'Gradually lower your heels back to the ground to complete one repetition.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(476,120,4,'Repeat this process for your desired number of repetitions, ensuring to maintain control throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(477,121,1,'Place one foot forward, keeping your knee bent, and the other foot back, straight and flat on the ground.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(478,121,2,'Slowly lean into the wall while keeping your back leg straight, heel flat on the floor, and the back foot pointed straight ahead.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(479,121,3,'Hold this stretch for about 30 seconds, feeling the stretch in the calf of the back leg.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(480,121,4,'After the time is up, switch legs and repeat the process.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(481,122,1,'Shift your weight onto one foot and lift the other foot off the ground, balancing yourself.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(482,122,2,'Slowly rise up onto the toes of your standing foot, lifting your heel as high as possible to engage your calf muscle.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(483,122,3,'Hold this position for a moment, ensuring your core is engaged and your body is balanced.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(484,122,4,'Slowly lower your heel back to the floor to complete one repetition, then switch to the other foot and repeat the process.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(485,123,1,'Place your hands on top of the lever pad in order to prevent it from slipping forward. This is your starting position.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(486,123,2,'Begin the exercise by raising your heels as you breathe out, extending your ankles as high as possible and flexing your calf muscles. Ensure your knees remain stationary at all times. Hold the contracted position briefly.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(487,123,3,'Slowly lower your heels by bending at the ankles until your calves are fully stretched, while you inhale.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(488,123,4,'Repeat the movement for the recommended amount of repetitions.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(489,124,1,'Position your feet shoulder-width apart, with your toes pointing straight ahead or slightly outward.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(490,124,2,'Slowly raise your heels off the ground, pushing up onto your toes while keeping your core engaged and your back straight.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(491,124,3,'Hold the position at the top for a moment, squeezing your calf muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(492,124,4,'Slowly lower your heels back down to the ground, returning to the starting position. Repeat the movement for the desired number of reps.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(493,125,1,'Hold onto the back of the chair with both hands for balance, ensuring your back is straight and your core is engaged.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(494,125,2,'Slowly lift your heels as high as you can, pushing up onto the balls of your feet and contracting your calf muscles.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(495,125,3,'Hold this position for a few seconds to feel the tension in your calves.',NULL);
INSERT OR REPLACE INTO "exercise_instruction" VALUES(496,125,4,'Gradually lower your heels back down below the level of the step or block to complete one repetition, and repeat this movement for your desired amount of reps.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(1,1,1,'Avoid Arching Your Back: One common mistake is excessively arching the back during the lift. This can lead to lower back injuries. Your lower back should have a natural arch, but it should not be overly exaggerated. Your butt, shoulders, and head should maintain contact with the bench at all times.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(2,1,2,'Controlled Movement: Avoid the temptation to lift the barbell too quickly. A controlled, steady lift is more effective and reduces the risk of injury. Lower the bar to your mid-chest slowly, pause briefly, then push it back up without locking your elbows at the top.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(3,1,3,'Don''t Lift Alone:',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(4,2,1,'Grip: Hold the dumbbells with a neutral grip (palms facing each other). This grip allows for a greater range of motion and less strain on the shoulders compared to a traditional grip. Avoid gripping the dumbbells too tightly as this can lead to wrist strain.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(5,2,2,'Elbow Alignment: When you lower the dumbbells, make sure your elbows are slightly below your shoulders. This alignment helps to engage the chest muscles effectively. A common mistake is allowing the elbows to flare out to the sides, which can lead to shoulder injuries.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(6,2,3,'Controlled Movement: Lower the dumbbells slowly and in a controlled manner,',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(7,3,1,'Maintain Proper Body Alignment: Your body should form a straight line from your head to your heels. Avoid arching your back or lifting your buttocks, as this can lead to back pain and reduce the effectiveness of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(8,3,2,'Controlled Movements: Avoid rushing through the movements. Lower your body in a controlled manner until your chest almost touches your hands, then push back up. This will ensure you''re fully engaging your muscles and not relying on momentum.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(9,3,3,'Don''t Lock Your Elbows: When you push your body up, avoid locking your elbows, as it can put unnecessary strain on your joints. Keep a slight bend in your elbows at the top of the movement.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(10,3,4,'Warm',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(11,4,1,'Proper Grip: Hold the dumbbell with a neutral grip, meaning your palms should be facing each other. This is where the ''hammer'' in the name comes from, as your hand positioning should resemble holding a hammer. Avoid gripping the dumbbell too tightly as this can lead to unnecessary forearm fatigue.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(12,4,2,'Controlled Movement: As you press the dumbbell upwards, ensure your movement is slow and controlled. Avoid the common mistake of using momentum to lift the weight, as this can lead to muscle strain and doesn''t effectively engage the targeted muscles. At the top of the movement, your arm should be fully extended but not locked out.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(13,5,1,'Controlled Movement: This exercise involves lowering the dumbbell until your elbow is at a 90-degree angle, then pressing it back up to the starting position. It''s important to perform this motion in a slow, controlled manner. Avoid the temptation to use momentum or to perform the exercise too quickly, as this can lead to poor form and potential injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(14,5,2,'Use Appropriate Weight: Using a weight that''s too heavy can compromise your form and increase your risk of injury. Start with a lighter weight and gradually increase as you get stronger. The last couple of reps should feel challenging, but you should still be able to maintain good form.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(15,5,3,'Avoid Locking Your Elbows: When pressing the dumbbell',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(16,7,1,'Proper Hand Position: Your hands should be slightly wider than shoulder-width apart. Avoid gripping the bar too wide or too narrow, as this can strain the shoulders and limit the effectiveness of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(17,7,2,'Controlled Movement: Lift and lower the weights in a slow, controlled manner. Avoid jerking the weights or using momentum to lift them, as this can lead to injury and reduces the effectiveness of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(18,7,3,'Avoid Locking Elbows: When you press the weights up, avoid locking your elbows at the top of the movement. This can put unnecessary strain on the joints and lead to injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(19,7,4,'Breathing Technique: Breathe in as you lower the weights and breathe out as you lift',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(20,8,1,'Controlled Movements: Avoid rushing through the movements. The Arnold Press should be performed slowly and controlled, both when lifting and lowering the weights. This not only ensures the targeted muscles are fully engaged, but also reduces the risk of injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(21,8,2,'Right Weight: Select a weight that is challenging but manageable. Using weights that are too heavy can lead to improper form and increase the risk of injury. On the other hand, weights that are too light might not provide enough resistance to effectively work the muscles.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(22,8,3,'Breathing Technique: Remember to breathe correctly. Inhale as you lower the weights',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(23,9,1,'Avoid Using Momentum: Another common mistake is using momentum to lift the weights. This not only reduces the effectiveness of the exercise, but it also increases the risk of injury. Focus on using your muscles to lift the weights, not the momentum of the swing.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(24,9,2,'Right Weight Selection: Choosing the right weight is crucial. If the weight is too heavy, it can lead to improper form and potential injury. Conversely, if it''s too light, you',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(25,10,1,'Engage Your Core: As you lower your body by bending your elbows, maintain a tight core. This helps to stabilize your body and protect your spine. A common mistake is to let the core go loose, which can cause strain on your back and shoulder muscles.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(26,10,2,'Proper Elbow Alignment: While lowering your body, ensure your elbows are bent at a 90-degree angle and pointing back, not flaring out to the sides. This is crucial for targeting the triceps effectively and avoiding unnecessary strain on the shoulders.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(27,10,3,'Controlled Movement: Avoid rushing through the movement. Lower your body in a slow, controlled manner and push back up to the starting position. This ensures',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(28,11,1,'Avoiding Knee Overextension: A common mistake is extending the knees too far forward, beyond the toes. This can put unnecessary pressure on the knees and lead to injury. Instead, make sure your knees are aligned with your feet during the squat.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(29,11,2,'Depth of Squat: Aim for a deep squat where your hips go below your knees. However, do not compromise on form or safety to achieve this. If you can''t squat that deep without losing form, it''s better to do a shallower squat.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(30,11,3,'Breathing Technique: Your breathing technique can greatly influence your performance. Inhale as you lower your body and exhale as you push yourself back up',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(31,12,1,'Foot Placement: Your feet should be slightly wider than shoulder-width apart, with toes pointing slightly outward. This provides a stable base for the squat. Avoid placing your feet too close together as it can make it difficult to maintain balance and can put undue stress on your knees.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(32,12,2,'Squat Depth: Aim to lower your body until your elbows touch your knees or your thighs are parallel to the floor. This ensures you''re getting the full range of motion and maximum benefits from the exercise. Avoid not going deep enough as it can limit the effectiveness of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(33,12,3,'Keep Your Chest Up and Back Straight: One common mistake is',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(34,13,1,'Controlled Movement: Avoid rushing the movements. Each step of the Squat Thrust should be performed in a controlled manner. Rushing can lead to sloppy form, which not only reduces the effectiveness of the exercise but also increases risk of injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(35,13,2,'Full Range of Motion: Make sure to perform the exercise through its full range of motion. When you squat, go as low as your flexibility allows, ideally until your thighs are parallel to the floor. When you kick back into the plank, extend your legs fully. Cutting these movements short can limit the benefits of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(36,13,3,'Keep the Core Engaged: Throughout the exercise, keep your core muscles engaged. This',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(37,14,1,'Proper Form: The key to an effective Sissy Squat is maintaining proper form throughout the movement. Stand upright with your feet shoulder-width apart. As you bend your knees to lower your body, lean your torso backwards to maintain balance. Keep your back straight and avoid hunching or arching it excessively as this can lead to back injuries.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(38,14,2,'Controlled Movement: A common mistake is rushing through the exercise or using momentum to complete the movement. Instead, perform each rep slowly and with control. This will engage your muscles more effectively and reduce the risk of injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(39,14,3,'Use Assistance if Needed: If you''re new to Sissy Squats',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(40,15,1,'Maintain Upright Posture: It''s important to keep your body upright throughout the movement. Leaning too far forward can put unnecessary strain on your lower back and shift the focus away from your lower body muscles.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(41,15,2,'Avoid Knee Overextension: Never let your front knee extend past your toes as you lower your body. This is a common mistake that can lead to knee injuries. Instead, make sure your knee is in line with your ankle.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(42,15,3,'Controlled Movement: Don''t rush the movement. Lower your body in a controlled manner and then push back up to the starting position. This will ensure that you''re effectively engaging your muscles and not relying on',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(43,16,1,'Squat Depth: When you squat down, make sure your thighs are at least parallel to the floor. Avoid the common mistake of not squatting deep enough, as this can limit the effectiveness of the exercise and place undue stress on your knees.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(44,16,2,'Explosive Jump: The key to this exercise is the jumping component. As you rise from the squat, push through your heels and explode upwards, jumping as high as possible. A common mistake is not jumping with enough force, which can limit the exercise''s effectiveness in strengthening your lower body and improving your vertical jump.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(45,16,3,'Controlled Landing: Land softly and quietly, absorbing the impact with your legs by bending your knees and returning to the squat position',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(46,17,1,'Keep Your Chest Up: One common mistake is leaning too far forward or allowing the back to round. To avoid this, focus on keeping your chest lifted and your spine neutral throughout the exercise. This will also engage your core muscles more effectively.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(47,17,2,'Depth of Squat: In a sumo squat, aim to lower your body until your thighs are parallel to the floor. Going too low (past parallel) can put undue stress on your knees, while not going low enough may not fully engage the muscles.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(48,17,3,'Knee Alignment: Ensure your knees are directly above your ankles when you squat down, not jutting forward over your toes. This will help to prevent knee injuries.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(49,17,4,'Push Through Your Heels: When coming back up to standing position, push',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(50,18,1,'Maintain Good Posture: Always keep your torso upright throughout the exercise. Leaning too far forward or backward can put unnecessary strain on your back, leading to potential injury. The chest should be up and the shoulders back.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(51,18,2,'Depth of the Squat: Aim for your front thigh to be parallel with the ground at the bottom of your squat. If you can''t reach this depth, it''s likely that your stance is too narrow. Conversely, if you''re going deeper than this, your stance might be too wide.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(52,18,3,'Don''t Let Your Knee Cave In: When you lower yourself into the squat, make sure your front knee is tracking over your foot. If your',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(53,19,1,'Correct Form: Maintain a correct posture throughout the exercise. Start with your feet shoulder-width apart, bend your knees and hips to lower your body into a squat, then explosively jump up. When you land, make sure to do so softly and go directly into the next squat. Keep your chest up and back straight, and don''t let your knees cave inwards.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(54,19,2,'Control Your Landing: A common mistake is landing hard on your feet, which can lead to injuries. Always aim to land softly and quietly, absorbing the impact through your legs. Your knees should be slightly bent upon landing.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(55,19,3,'Use Your Arms: Your arms can help you generate more power and maintain balance. As you squat',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(56,20,1,'Controlled Movements: One common mistake is rushing through the exercise. Make sure to perform the movement slowly and with control, lowering yourself as far as you can comfortably go, then pushing back up to the starting position. This enhances muscle engagement and reduces the risk of injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(57,20,2,'Keep Core Engaged: Your core should be tight throughout the exercise. This will help you maintain balance and stability, especially since you''re performing the exercise on a single leg. Avoid letting your torso lean too far forward or sideways as this can lead to an incorrect form and potential injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(58,20,3,'',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(59,21,1,'Maintain a Neutral Spine: One common mistake is rounding the back during the movement, which can lead to injury. Instead, keep your back straight and your core engaged throughout the exercise. Your shoulders should be back and down, not hunched.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(60,21,2,'Hinge at the Hips: The Romanian Deadlift is a hip-hinge movement, meaning the action comes from bending at the hips, not the waist. Push your hips back as you lower the weights towards the ground, keeping them close to your legs to avoid straining your lower back.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(61,21,3,'Don’t Lock Your Knees: Another common mistake is to lock your knees during the exercise. Your',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(62,22,1,'Correct Foot Placement: Stand with your feet shoulder-width apart. Do not position your feet too wide or too narrow as it can compromise your balance and the effectiveness of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(63,22,2,'Controlled Movements: Lower the dumbbells slowly and controlled, hinging at the hips. Avoid the mistake of using a fast, jerking motion to lift the weights. This can lead to muscle strain and does not effectively work the targeted muscles.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(64,22,3,'Right Weight: Choose a weight that is challenging but manageable. One common mistake is lifting too heavy too soon, which can compromise form and lead to injury. Start with lighter weights and gradually increase as your strength improves.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(65,22,4,'Engage Your Core: Keep your abs braced throughout the exercise. This',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(66,23,1,'Arm and Leg Extension: As you lower your body, extend your non-supporting leg and the opposite arm in a straight line. This requires balance and coordination, so take your time and don''t rush the movement. The common mistake is to let the arm or the leg droop, which can throw off your balance and alignment.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(67,23,2,'Controlled Movements: This exercise is not about speed, but control. Lower your body slowly, and then push back up to the starting position in a controlled manner. Avoid jerky movements which can lead to muscle strain or injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(68,23,3,'Don''t Lock the Knee: Keep a slight bend in your',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(69,24,1,'Avoid Overextending: A common mistake is to lower the weights too far, which can strain the lower back. Aim to lower the weights to just below your knees or until you feel a stretch in the hamstrings, then return to the starting position.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(70,24,2,'Engage Your Core and Glutes: To get the most out of the exercise, it''s important to engage your core and squeeze your glutes as you lift the weights back up. This will help to stabilize your body and increase the effectiveness of the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(71,24,3,'Don''t Rush: Another mistake to avoid is rushing',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(72,25,1,'Keep Your Focus: Balance is key in this exercise. To help maintain balance, find a fixed point in front of you and keep your gaze on it throughout the movement. This will help you stay steady and ensure you are performing the exercise correctly.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(73,25,2,'Use Your Hips: The single leg deadlift is a hip hinge movement, meaning the action should come from your hips, not your knees. Push your hips back as you lower your body and drive them forward as you return to the standing position.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(74,25,3,'Avoid Rushing: Many people rush through the exercise, which can lead to a loss of balance and poor form. Take your time with each repetition',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(75,26,1,'Full Foot Contact: Ensure your entire foot, from heel to toe, is in contact with the pedal throughout the movement. Some people tend to push through their toes, which can strain the calf muscles and reduce the overall effectiveness of the workout.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(76,26,2,'Use the Handles: The handles are there to help engage your upper body. However, avoid pulling on them with too much force as this can lead to an imbalance and strain your arms. Instead, lightly grip the handles and use them to guide your motion.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(77,26,3,'Appropriate Resistance and Speed: Start with a low resistance level and gradually increase it as your strength and endurance improve. Avoid setting the resistance too high as it can lead to strain and injury. Similarly, don''t',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(78,27,1,'Warm Up and Cool Down: Always start your workout with a 5 to 10 minute warm-up at a slower pace to get your muscles ready for the exercise. Similarly, end your session with a cool-down period to gradually reduce your heart rate and prevent muscle stiffness.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(79,27,2,'Gradual Increase in Speed and Incline: Don''t start walking at a high speed or incline. Begin your workout at a comfortable pace and gradually increase the intensity. This will help prevent injuries and ensure that you don''t burn out too quickly.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(80,27,3,'Avoid Overstriding: A common mistake is taking long strides to increase the speed or to make the',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(81,28,1,'Correct Foot Placement: Your feet should be flat on the pedals at all times. This will help you engage more muscles and reduce the risk of injury. Avoid pushing through your toes, which can lead to foot or calf discomfort.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(82,28,2,'Hand Placement: If your elliptical machine has handles, use them to work your upper body. However, make sure not to grip them too tightly or lean on them, as this can put unnecessary strain on your wrists and arms.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(83,28,3,'Use the Resistance and Incline Settings: One common mistake is not utilizing the various settings on the elliptical. Adjusting the resistance and incline can help you target different muscle groups and add variety to your workout, making it more',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(84,29,1,'Avoid Holding onto the Handrails: One of the common mistakes people make is holding onto the handrails while running. This can lead to an unnatural running form and limit the amount of calories you burn. Instead, let your arms swing naturally as they would if you were running outdoors.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(85,29,2,'Use the Incline Wisely: To mimic outdoor running, set your incline to at least 1-2%. Running on a flat treadmill can be easier than running outside because there''s no wind resistance. However, don''t set the incline too high (over 7%) as this can be hard on your back, hips, and ankles.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(86,29,3,'Don''t Look Down: Looking down or watching your feet while running',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(87,30,1,'Gradual Increase: Start with a small incline and gradually increase it over time. This will allow your body to adjust to the new exercise intensity and reduce the risk of injury.    Common Mistake: Suddenly increasing the incline can lead to muscle strains or other injuries.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(88,30,2,'Appropriate Speed: Don''t try to maintain the same speed you use on a flat surface. The incline makes the exercise more challenging, so you''ll likely need to slow down to maintain a steady pace.    Common Mistake: Attempting to walk too fast on an incl',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(89,31,1,'Engage Your Core: To get the most out of the Suspended Row, it''s important to engage your core throughout the entire exercise. This not only helps to stabilize your body but also maximizes the strength you can gain from the exercise. A common mistake is to focus only on pulling with your arms, while ignoring your core.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(90,31,2,'Controlled Movement: Ensure that your movements are slow and controlled. Avoid the temptation to use momentum to pull yourself up, as this can lead to injury and makes the exercise less effective. Instead, focus on pulling yourself up using your',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(91,32,1,'Controlled Movements: When you pull the weight up, do so in a controlled manner, ensuring that your elbow is close to your body. Similarly, lower the weight in a controlled manner. Avoid jerky or fast movements, as this can lead to muscle strain and doesn''t effectively work the targeted muscles.',NULL);
