INSERT OR REPLACE INTO "exercise_tip" VALUES(212,72,1,'Avoid Using Momentum: Avoid using momentum to swing the weights up, as this can lead to injury and reduces the effectiveness of the exercise. Instead, lift and lower the weights in a controlled manner, focusing on the muscles you''re trying to work.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(213,72,2,'Choose the Right Weight: Using too heavy weights can lead to poor form and potential injuries. Start with lighter weights and gradually increase as your strength improves. Remember, the goal is not to lift the heaviest weight, but to perform the exercise correctly and safely.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(214,72,3,'Focus on the Shoulders: The lateral raise primarily targets the shoulder muscles, specifically the',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(215,73,1,'Controlled Movement: Avoid bouncing or using momentum to lift the weight. This is a common mistake that can lead to injury and also reduces the effectiveness of the exercise. Instead, lift and lower the weight in a slow, controlled manner, focusing on the muscle contraction and relaxation.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(216,73,2,'Full Range of Motion: Make sure to use the full range of motion. Lower your heels as much as you can to stretch your calves, then lift as high as possible to contract them. Not using the full range of motion can limit the benefits of the exercise.',NULL);
