INSERT OR REPLACE INTO "exercise_tip" VALUES(246,83,1,'Avoid Leaning Forward: A common mistake to avoid is leaning forward. This can put unnecessary strain on your lower back and knees. Instead, try to keep your torso upright throughout the movement. If you find yourself leaning forward, it might be a sign that you''re trying to lunge too far forward.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(247,83,2,'Mind Your Pace: Don''t rush through your lunges. Performing them at a slow, controlled pace will help you maintain balance and focus on your form. It also ensures that your muscles are fully engaged throughout the exercise.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(248,83,3,'Even Distribution of Weight: Make sure to distribute your weight evenly between both',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(249,84,1,'Core Engagement: Engage your core throughout the exercise. This will help maintain balance and stability, and also protect your lower back from strain. It''s a common mistake to let your core relax, causing a bend or arch in your back, which can lead to injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(250,84,2,'Avoid Leaning Forward: One common mistake is to lean forward during the lunge. This can put unnecessary strain on your knees and back. Keep your body upright and your shoulders back to avoid this.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(251,84,3,'Don''t Rush: Perform the',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(252,86,1,'Avoid Leaning Forward: One common mistake many people make when performing reverse lunges is leaning too far forward, which can put unnecessary strain on your back and knees. To avoid this, focus on keeping your torso upright and your weight evenly distributed between both legs.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(253,86,2,'Core Engagement: Engage your core throughout the entire movement. This not only helps with balance but also works your abdominal muscles.',NULL);
