INSERT OR REPLACE INTO "exercise_tip" VALUES(255,87,1,'Avoid Leaning Forward: A common mistake is leaning too far forward when performing a side lunge. This can put unnecessary stress on your knees and back. Instead, keep your chest lifted and your spine neutral throughout the movement.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(256,87,2,'Control Your Movement: Side lunges should be done in a controlled manner. Avoid rushing through the movement or using momentum to carry you from side to side. This will ensure you''re effectively working your muscles and not risking injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(257,87,3,'Mind Your Knee Alignment: When you''re in the lunge, make sure your knee',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(258,88,1,'Controlled Movement: As you lower your body towards the ground, keep your elbows close to your body. Push back up, and as you do, rotate your upper body to one side, lifting the same-side arm towards the ceiling. Repeat the movement, alternating sides. Avoid rushing through the movements. Each phase of the push-up should be done in a slow, controlled manner to maximize muscle engagement and prevent injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(259,88,2,'Core Engagement: Keep your core engaged throughout the exercise. This will not only help to stabilize your body but also enhance the effectiveness of the push-up. A common mistake is to forget',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(260,89,1,'Correct Positioning: Start by kneeling on one knee with your other foot in front of you, toes pointing upwards. Your front leg should be straight, and your back should be upright. Avoid arching your back or bending your front leg, as these are common mistakes that can lead to injury or reduce the effectiveness of the stretch.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(261,89,2,'Gradual Stretch: Lean forward from your hips, keeping your back straight, until you feel a stretch in the hamstring of your front leg. Don''t bounce or force the stretch - this is a common mistake that can cause muscle strain. The stretch should be gradual and controlled.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(262,89,3,'Hold and Breathe: Hold the stretch for at least 15-30',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(263,90,1,'Controlled Movements: Avoid flailing or uncontrolled movements. Each punch should be deliberate and controlled. Extend your arm fully but don''t lock your elbow when you punch. This can lead to injury. Instead, keep a slight bend in your elbow even at the end of the punch.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(264,90,2,'Body Rotation: A common mistake is to only use the arms while punching. The power of a punch actually comes from the rotation of your body. As you punch, twist your torso and pivot on your back foot. This will not only add power to your punch but also engage your core muscles.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(265,90,3,'Breathing: Don''t hold your breath while punching. Exhale with each punch and inhale as you',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(266,91,1,'Slow and Steady Movement: Lower the weights slowly towards your forehead by bending at the elbows. The weights should be lowered until they''re about an inch from your forehead. Avoid the common mistake of moving your upper arms; they should remain stationary throughout the exercise. Rushing through the movement can lead to poor form and less effective muscle engagement.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(267,91,2,'Proper Elbow Alignment: Your elbows should be pointed towards your feet and not flaring out to the sides. This is a common mistake that can lead to shoulder strain. Keeping your elbows in helps to better isolate the triceps.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(268,91,3,'Engage Your Core: While the focus is on your arms, don',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(269,92,1,'Correct Posture: One common mistake is incorrect posture. Make sure to sit upright on the bike, with your chest out and shoulders back. Avoid hunching over as this can lead to back strain. Also, ensure that your feet are flat on the pedals and your hands are gripping the handles firmly but not too tightly.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(270,92,2,'Balanced Effort: The Assault Bike Run is a full-body workout, so it''s essential to use both your arms and legs equally. A common mistake is to rely too much on either the upper or lower body. To avoid this, focus on pushing and pulling the handles while also pedaling with your legs.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(271,92,3,'Pacing: Avoid starting off too fast. It''s better to start with a moderate pace',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(272,93,1,'Proper Form: Make sure your form is correct. Stand tall with your feet hip-width apart. As you bend forward to touch your toes, keep your back straight and bend from your hips, not your waist. A common mistake is rounding the back, which can lead to strain or injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(273,93,2,'Don''t Force It: Never force your body to reach your toes if it''s not possible initially. It''s okay if you can''t touch your toes. The goal is to feel a stretch in your hamstrings, not to reach your toes. Over time, as your flexibility improves, you''ll be able to reach further.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(274,93,3,'Breathe: Remember to breathe normally throughout the exercise. Holding your breath',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(275,94,1,'Controlled Movements: It''s crucial to perform the exercise with slow, controlled movements. Rushing through the movements can lead to improper form and potential injury. When transitioning from your forearms to your hands, make sure to keep your core engaged and your body in a straight line. Avoid swaying or dipping your hips, which is a common mistake.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(276,94,2,'Elbow Alignment: When you push up from your forearms, ensure your elbow aligns directly under your shoulder. This helps to avoid unnecessary strain on your shoulder joints. A common mistake is to place the hands too far forward, causing the elbows to move out of alignment.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(277,94,3,'Breathing: It''s',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(278,95,1,'Controlled Movement: When performing the toe tap, make sure to move your leg out to the side in a controlled manner, tap your toe to the ground, and then bring it back to the starting position. Avoid rushing through the movement or using momentum, as this can lead to improper form and potential injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(279,95,2,'Engage Core: Keep your core engaged throughout the entire exercise to stabilize your body. This not only helps to protect your lower back but also maximizes the effectiveness of the exercise. A common mistake is to let the core relax, which can strain the lower back.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(280,95,3,'Keep Neck Neutral: Avoid straining your neck by looking too far up or down. Keep your gaze down',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(281,96,1,'Controlled Movement: When performing the leg lift, it''s crucial to keep your movements controlled and deliberate. Avoid swinging or jerking your leg upwards as this can strain your lower back and won''t effectively engage the targeted muscles. Lift your leg only to a height that allows you to maintain a straight back and engaged core.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(282,96,2,'Core Engagement: The front plank with leg lift is a core exercise, so ensure your abs, glutes, and back muscles are engaged throughout the entire movement. If your hips sag or your back arches, it''s a sign that your core is not properly engaged, which can lead to injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(283,96,3,'Breathing: Another common mistake is holding your breath during',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(284,97,1,'Controlled Movements: Slowly push your foot down, as if pressing on a gas pedal, then slowly return to the starting position. The key here is to perform the movement in a controlled manner, avoid jerky or rushed motions which can lead to injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(285,97,2,'Consistent Repetitions: Aim for consistency in your repetitions. A common mistake is to do too many reps too quickly. Instead, focus on doing a set number of repetitions, such as 10 to 15, and gradually increase as your strength improves.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(286,97,3,'Avoid Overextension: A common mistake is to push too hard, leading to overextension of the ankle. This can result in strain or injury. Always listen to your body and stop if you feel any pain.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(287,97,4,'Use of',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(288,98,1,'Correct Positioning: Make sure to position your foot correctly. Your heel should be firmly on the ground, and your toes should be pointing upwards. Avoid any sideways movement as it can lead to ankle sprains.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(289,98,2,'Controlled Movements: The most common mistake is to rush through the exercise. It''s essential to perform each movement slowly and with control. Rapid or jerky movements can lead to injuries.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(290,98,3,'Use of Props: If you''re having trouble performing the exercise, consider using a towel or resistance band. Place the prop around the ball of your foot and gently pull towards you to help with the upward movement.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(291,98,4,'Regular Breaks: Don''t overdo it. If you feel any pain or discomfort, stop the exercise immediately. It',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(292,99,1,'Proper Form: When stretching, make sure your form is correct. For a basic ankle stretch, sit on the floor with your legs extended in front of you. Reach forward with your hands and gently pull your toes back towards your body. Make sure to keep your back straight and don''t hunch over to reach your feet. This will ensure you''re stretching your ankles and not straining your back.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(293,99,2,'Gradual Stretch: Avoid bouncing or jerky movements when stretching. These can cause micro-tears in the muscle, leading to pain and injury. Instead, gradually increase the stretch over a period of 15-30 seconds. This allows your muscles',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(294,100,1,'Proper Posture: Ensure that you maintain the right posture while performing the feet and ankles stretch. Stand tall with your feet hip-width apart and your weight evenly distributed on both feet. Avoid leaning too far forward or backward, as this can strain your muscles and lead to injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(295,100,2,'Gradual Stretching: When stretching your feet and ankles, make sure to do it gradually. Avoid bouncing or making jerky movements, which can cause injury. Instead, hold each stretch for about 20 to 30 seconds, release, and then repeat.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(296,100,3,'Listen to Your Body: While it''s normal to feel a gentle pull or slight discomfort when stretching, you should never feel pain.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(297,101,1,'Correct Posture: While performing the feet and ankles rotation stretch, make sure you are in the correct posture. You can sit or stand, but your back should be straight. A common mistake is to slouch or lean too much into the stretch which can cause strain.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(298,101,2,'Controlled Movement: Make sure your rotations are slow and controlled. Avoid jerky movements as they can lead to injuries. The key here is to focus on the quality of the movement rather than the quantity.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(299,101,3,'Both Directions: It''s important to rotate your feet and ankles in both directions to ensure balanced stretching. A common mistake is to only rotate in one direction, which can lead to imbalances.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(300,101,4,'Don''t Overstretch: Stretch',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(301,102,1,'Correct Positioning: Start the exercise by sitting on the floor with your legs extended in front of you. Keep your back straight and avoid slouching. This position will help you stretch your feet and ankles effectively without straining your back.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(302,102,2,'Controlled Movements: When moving your feet and ankles side to side, make sure to do so in a controlled manner. Avoid quick, jerky movements as these can lead to sprains or strains. Instead, focus on slow, deliberate movements that allow you to feel the stretch.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(303,102,3,'Don''t Overstretch: Stretch to the point of mild tension, not pain. If you feel pain, you''re stretching too far. Overstretching can cause injury to your muscles and ligaments.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(304,102,4,'Regular Practice',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(305,103,1,'Maintain Proper Form: Start in a traditional push-up position, with your body forming a straight line from your head to your heels. When you push up, propel your body upwards with enough force to clap your hands together before landing. It''s crucial to maintain proper form throughout the exercise, as incorrect form can lead to injury.',NULL);
INSERT OR REPLACE INTO "exercise_tip" VALUES(306,103,2,'Land Softly: One common mistake is landing too hard after the clap. This can be harmful to your wrists and elbows. To avoid this, make sure to land softly with your elbows slightly bent to absorb the shock.',NULL);
